mapper.select:
SELECT c.id, c.content, c.article_id, c.user_id, c.parent_id, c.reply_to_id, c.status, c.create_time, u.id as uid, u.nickname as unickname, u.avatar as uavatar, ru.id as ruid, ru.nickname as runickname FROM comment c LEFT JOIN user u ON c.user_id = u.id LEFT JOIN user ru ON c.reply_to_id = ru.id WHERE c.parent_id IN
#{pid}
AND c.status = 1 ORDER BY c.create_time ASC
